const input = $input.first().json;
return [{
  json: {
    ...input,
    _config: {
      S3_BUCKET: 'fiche-auto-cache',
      S3_REGION: 'eu-west-3',
      PERPLEXITY_MODEL: 'sonar-pro',
      LLM_MODEL: 'gpt-4.1-mini',
      IMAGE_MODEL: 'gpt-image-1'
    }
  }
}];

const input = $input.first().json;
const plaque = (input.query?.plaque || input.body?.plaque || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
return [{ json: { plaque, s3_prefix: `plaques/${plaque}` } }];

const item = $input.first();
let hasCache = false;
try {
  if (item.binary && item.binary.data) {
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    if (buffer && buffer.length > 10) {
      hasCache = true;
    }
  }
} catch (e) {
  hasCache = false;
}
return [{
  json: { hasCache, plaque: $('Normalize Plaque').item.json.plaque, s3_prefix: $('Normalize Plaque').item.json.s3_prefix },
  binary: item.binary
}];

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const cached = JSON.parse(buffer.toString('utf-8'));
return [{ json: { ...cached, cache: 'hit' } }];

const xml = $input.first().json.data;
const match = xml.match(/<vehicleJson>([\s\S]*?)<\/vehicleJson>/);

if (!match || !match[1]) {
  throw new Error('RegCheck: vehicleJson introuvable dans la réponse XML');
}

const vehicle = JSON.parse(match[1]);
const ext = vehicle.ExtendedData || {};

return [{ json: {
  regcheck_raw: vehicle,
  marque:      vehicle.CarMake?.CurrentTextValue  || ext.marque         || vehicle.MakeDescription?.CurrentTextValue  || '',
  modele:      vehicle.CarModel?.CurrentTextValue || ext.modele         || vehicle.ModelDescription?.CurrentTextValue || '',
  finition:    ext.version                        || ext.libVersion     || '',
  annee:       vehicle.RegistrationYear           || ext.anneeSortie    || '',
  carburant:   vehicle.FuelType?.CurrentTextValue || ext.carburantVersion || '',
  motorisation: ext.libVersion                   || ext.version        || ''
}}];

const reg = $('Parse RegCheck').item.json;
const ppx = $('Perplexity Specs').item.json.choices[0].message.content;
const plaque = $('Normalize Plaque').item.json.plaque;
const model = $('Config').item.json._config.LLM_MODEL;

const n = (t) => ({ anyOf: [{ type: t }, { type: 'null' }] });

const schema = {
  type: 'object',
  properties: {
    informations_generales: { type: 'object', properties: {
      marque: { type: 'string' }, modele: { type: 'string' },
      generation: n('string'), phase: n('integer'),
      annee: n('integer'), version: n('string'), finition: n('string'),
      categorie: n('string'), nombre_portes: n('integer'), nombre_places: n('integer'),
      transmission: n('string'), boite_vitesse: n('string')
    }, required: ['marque','modele','generation','phase','annee','version','finition','categorie','nombre_portes','nombre_places','transmission','boite_vitesse'], additionalProperties: false },

    dimensions: { type: 'object', properties: {
      longueur_mm: n('integer'), largeur_mm: n('integer'), hauteur_mm: n('integer'),
      empattement_mm: n('integer'), poids_vide_kg: n('integer'), ptac_kg: n('integer'),
      volume_coffre_min_l: n('integer'), volume_coffre_max_l: n('integer')
    }, required: ['longueur_mm','largeur_mm','hauteur_mm','empattement_mm','poids_vide_kg','ptac_kg','volume_coffre_min_l','volume_coffre_max_l'], additionalProperties: false },

    motorisation: { type: 'object', properties: {
      type_moteur: n('string'), cylindree_cm3: n('integer'),
      nombre_cylindres: n('integer'), architecture: n('string'),
      puissance_ch: n('integer'), puissance_kw: n('integer'), puissance_regime_rpm: n('integer'),
      couple_nm: n('integer'), couple_regime_rpm: n('string'),
      alimentation: n('string'), norme_euro: n('string')
    }, required: ['type_moteur','cylindree_cm3','nombre_cylindres','architecture','puissance_ch','puissance_kw','puissance_regime_rpm','couple_nm','couple_regime_rpm','alimentation','norme_euro'], additionalProperties: false },

    performances: { type: 'object', properties: {
      zero_cent_sec: n('number'), vitesse_max_kmh: n('integer')
    }, required: ['zero_cent_sec','vitesse_max_kmh'], additionalProperties: false },

    energie: { type: 'object', properties: {
      type_carburant: n('string'), reservoir_l: n('number'),
      consommation_mixte_l100: n('number'),
      consommation_urbaine_l100: n('number'),
      consommation_extra_urbaine_l100: n('number'),
      emissions_co2_gkm: n('integer'), cycle_emissions: n('string'),
      norme_euro: n('string')
    }, required: ['type_carburant','reservoir_l','consommation_mixte_l100','consommation_urbaine_l100','consommation_extra_urbaine_l100','emissions_co2_gkm','cycle_emissions','norme_euro'], additionalProperties: false },

    roues: { type: 'object', properties: {
      taille_jantes_pouces: n('integer'), jantes_alliage: n('boolean'),
      pneus_avant: n('string'), pneus_arriere: n('string')
    }, required: ['taille_jantes_pouces','jantes_alliage','pneus_avant','pneus_arriere'], additionalProperties: false },

    equipements: { type: 'object', properties: {
      ecran_tactile_pouces: n('number'), combine_numerique_pouces: n('number'),
      apple_carplay: n('boolean'), android_auto: n('boolean'),
      gps_integre: n('boolean'), bluetooth: n('boolean'), chargeur_induction: n('boolean'),
      camera_recul: n('boolean'), radar_recul: n('boolean'), radar_avant: n('boolean'),
      aide_stationnement_auto: n('boolean'),
      regulateur_vitesse: n('boolean'), regulateur_adaptatif: n('boolean'), limiteur_vitesse: n('boolean'),
      alerte_franchissement_ligne: n('boolean'), aide_maintien_voie: n('boolean'),
      surveillance_angles_morts: n('boolean'), freinage_urgence_auto: n('boolean'),
      reconnaissance_panneaux: n('boolean'), alerte_trafic_transversal: n('boolean'),
      feux_avant_type: n('string'), feux_arriere_type: n('string'), allumage_auto_feux: n('boolean'),
      climatisation: n('string'), sellerie: n('string'),
      sieges_chauffants: n('boolean'), sieges_electriques: n('boolean'), volant_chauffant: n('boolean'),
      keyless_entry: n('boolean'), keyless_start: n('boolean'),
      toit_ouvrant: n('boolean'), toit_panoramique: n('boolean'),
      retros_rabattables_elec: n('boolean')
    }, required: [
      'ecran_tactile_pouces','combine_numerique_pouces',
      'apple_carplay','android_auto','gps_integre','bluetooth','chargeur_induction',
      'camera_recul','radar_recul','radar_avant','aide_stationnement_auto',
      'regulateur_vitesse','regulateur_adaptatif','limiteur_vitesse',
      'alerte_franchissement_ligne','aide_maintien_voie','surveillance_angles_morts',
      'freinage_urgence_auto','reconnaissance_panneaux','alerte_trafic_transversal',
      'feux_avant_type','feux_arriere_type','allumage_auto_feux',
      'climatisation','sellerie','sieges_chauffants','sieges_electriques','volant_chauffant',
      'keyless_entry','keyless_start','toit_ouvrant','toit_panoramique','retros_rabattables_elec'
    ], additionalProperties: false },

    image_prompt: { type: 'string' }
  },
  required: ['informations_generales','dimensions','motorisation','performances','energie','roues','equipements','image_prompt'],
  additionalProperties: false
};

const systemPrompt = `Tu es un extracteur de données automobiles.
Tu reçois des textes bruts contenant des informations techniques sur un véhicule.
Tu dois extraire ces informations et les retourner en JSON valide.

RÈGLES :
- Pour les valeurs numériques introuvables ou marquées "inconnu" : null
- Pour les textes introuvables ou marqués "inconnu" : null
- Pour les booléens marqués "Absent" ou "Non" : false
- Pour les booléens marqués "De série" ou "Oui" : true
- Pour les booléens marqués "inconnu" : null
- N'invente AUCUNE valeur
- Si deux sources se contredisent : préfère RegCheck pour les données administratives (marque, modèle, puissance fiscale, CO2, cylindrée) et Perplexity pour les données techniques détaillées (dimensions, équipements, performances)
- Pour emissions_co2_gkm : TOUJOURS préférer la valeur RegCheck (donnée administrative officielle)
- Pour puissance_kw : si seule la valeur en ch est donnée, calcule kW = ch × 0.7355 arrondi à l'entier
- Pour couple_nm : si un couple combiné (thermique + électrique) est disponible, utilise-le. Sinon utilise le couple thermique seul
- Pour ecran_tactile_pouces : extrais la taille en pouces directement (ne convertis PAS en cm)
- Pour couple_regime_rpm : retourne une string (ex: "1500-3500")

MAPPING BOOLÉENS — RÈGLES SUPPLÉMENTAIRES :
- "de série", "oui", "standard", "inclus", "présent", "disponible" → true
- "absent", "non", "non disponible", "non proposé", "pas disponible" → false
- "en option", "optionnel" → false (seul l'équipement de série compte)
- Si le texte mentionne un équipement suivi de "(sans fil)" ou "(filaire)" → true
- Si le texte mentionne un sigle (LDW, LKA, BSM, AEB, RCTA, ACC, TSR) comme présent → true pour le champ correspondant

DÉDUCTIONS LOGIQUES (appliquer systématiquement) :
- Si regulateur_adaptatif = true → regulateur_vitesse = true
- Si aide_maintien_voie = true → alerte_franchissement_ligne = true
- Si keyless_start = true → keyless_entry = true (sauf indication contraire)

EXTRACTION DES POUCES :
- "écran 12,3 pouces" → 12.3
- "écran 10,25"" → 10.25
- "écran de 8 pouces" → 8.0
- Cherche le nombre associé à "pouces", "inches", le symbole " ou ″

VERSION ET FINITION :
- Le champ "version" est la dénomination commerciale complète du véhicule (ex: "1.6 T-GDi 265 N DCT", "2.0 BlueHDi 130 EAT8", "E 220d 4MATIC AMG Line")
- Cherche cette info dans RegCheck en priorité (champ Description, Version, libVersion ou Variant)
- Le champ "finition" est le nom commercial de la finition, extrait du dernier mot ou groupe de mots de la version (ex: "1.6 T-GDI HYBRID 215 INITIA" → finition = "INITIA", "2.0 BlueHDi 130 EAT8 Allure" → finition = "Allure", "E 220d 4MATIC AMG Line" → finition = "AMG Line")
- Si la finition est mentionnée dans le titre de la section équipements Perplexity, utilise-la en confirmation

VALEURS "non confirmé" :
- Si Perplexity renvoie "non confirmé : [valeur]", extrais la valeur entre crochets et utilise-la (elle est probable et préférable à null)

Pour image_prompt : prompt anglais au format :
"[YEAR] [BRAND] [MODEL] [COLOR or orange] [BODY_TYPE], professional automotive photography, 3/4 front view, neutral background, natural daylight, ultra realistic, 8k"`;

const userPrompt = 'Véhicule : ' + plaque + '\n\n### SOURCE 1 — RegCheck\n' + JSON.stringify(reg.regcheck_raw, null, 2) + '\n\n### SOURCE 2 — Perplexity\n' + ppx + '\n\nExtrais toutes les informations dans le JSON structuré.';

return [{
  json: {
    openai_body: JSON.stringify({
      model: model,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      response_format: {
        type: 'json_schema',
        json_schema: { name: 'fiche_technique', strict: true, schema: schema }
      },
      temperature: 0
    })
  }
}];

const content = $input.first().json.choices[0].message.content;
let parsed;
try {
  let cleaned = content.trim();
  if (cleaned.startsWith('`')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?```\s*$/, '');
  }
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('LLM: JSON invalide - ' + e.message);
}
if (parsed.output) parsed = parsed.output;
return [{ json: { output: parsed } }];

const extracted = $('Parse LLM Response').item.json.output || {};

const plaque = $('Normalize Plaque').item.json.plaque;
const s3_prefix = $('Normalize Plaque').item.json.s3_prefix;
const cfg = $('Config').item.json._config;
const regcheck = $('Parse RegCheck').item.json.regcheck_raw || {};

// Image URL is set optimistically — the parallel branch uploads it to S3
const image_url = `https://${cfg.S3_BUCKET}.s3.${cfg.S3_REGION}.amazonaws.com/${s3_prefix}/photo.png`;

const allFields = Object.values(extracted)
  .flatMap(section =>
    typeof section === 'object' && section !== null
      ? Object.entries(section)
      : []
  );
const totalFields = allFields.length;
const nullFields = allFields.filter(([k, v]) => v === null).map(([k]) => k);
const nonNullCount = totalFields - nullFields.length;
const score = totalFields > 0 ? Math.round((nonNullCount / totalFields) * 100) : 0;

const fiche = {
  ...extracted,
  plaque,
  image_url,
  sources: {
    regcheck_vehicule_id: regcheck.VehicleId || null,
    regcheck_vin: regcheck.Vin || null
  },
  qualite: {
    score_completude: score,
    total_champs: totalFields,
    champs_renseignes: nonNullCount,
    champs_null: nullFields
  },
  generated_at: new Date().toISOString(),
  cache: 'miss'
};

const jsonBuf = Buffer.from(JSON.stringify(fiche, null, 2), 'utf-8');
return [{
  json: { fiche, s3_prefix },
  binary: {
    data_json: await this.helpers.prepareBinaryData(jsonBuf, 'data.json', 'application/json')
  }
}];

const reg = $('Parse RegCheck').item.json;
const marque = reg.marque || 'car';
const modele = reg.modele || '';
const annee = reg.annee || '';
const prompt = `${annee} ${marque} ${modele} orange, professional automotive photography, 3/4 front view, neutral background, natural daylight, ultra realistic, 8k`;
return [{ json: { image_prompt: prompt.trim() } }];

const inputItem = $input.first();
const s3_prefix = $('Normalize Plaque').item.json.s3_prefix;

// Pass through the binary from Generate Image + the s3_prefix needed by S3 Upload Photo
return [{
  json: { s3_prefix },
  binary: inputItem.binary
}];
